    16|    case notConfigured
    17|    case httpError(Int, String)
    18|    case invalidCredentials
    19|    case emailNotConfirmed
    20|    case rateLimited
    21|    case networkFailure(String)
    22|
    23|    var errorDescription: String? {
    24|        switch self {
    25|        case .badURL: return "Invalid Supabase Auth endpoint URL."
    26|        case .notConfigured: return "Supabase is not configured. Rebuild the app with valid credentials."
    27|        case .httpError(let code, let message): return message.isEmpty ? "Sign-in failed (HTTP \(code))." : message
    28|        case .invalidCredentials: return "Invalid email or password. Please check your credentials and try again."
    29|        case .emailNotConfirmed: return "Your email is not confirmed yet. Confirm your email before signing in."
    30|        case .rateLimited: return "Too many sign-in attempts. Please wait a minute and try again."
    31|        case .networkFailure(let message): return message
    32|        }
    33|    }
