   158|    if (!legacy) return null;
   159|    await AsyncStorage.setItem(key, legacy);
   160|    try { await SecureStore.deleteItemAsync(key); } catch {}
   161|    console.log('[Supabase] Migrated legacy SecureStore session to AsyncStorage for key:', key);
